(() => {
  const svg = d3.select('svg');
  const root = svg.select('g'); // translated plot group

  // Ensure scene-2 layer exists
  const annLayer = root.select('g.annotation-layer.operation-next-annotation-layer');
  let scene2 = annLayer.select('g.scene-2-annotation');
  if (scene2.empty()) {
    scene2 = annLayer.append('g').attr('class', 'scene-2-annotation').attr('pointer-events', 'none');
  }

  // Helper: map x -> {obamaY, romneyY, obamaCircle, romneyCircle}
  const obamaCircles = root.selectAll('g[data-series="Obama"] circle');
  const romneyCircles = root.selectAll('g[data-series="Romney"] circle');

  const byX = new Map();
  obamaCircles.each(function() {
    const c = d3.select(this);
    const x = +c.attr('cx');
    byX.set(x, { x, obamaY: +c.attr('cy'), obamaCircle: c });
  });
  romneyCircles.each(function() {
    const c = d3.select(this);
    const x = +c.attr('cx');
    const obj = byX.get(x) || { x };
    obj.romneyY = +c.attr('cy');
    obj.romneyCircle = c;
    byX.set(x, obj);
  });

  const pairs = Array.from(byX.values())
    .filter(d => Number.isFinite(d.obamaY) && Number.isFinite(d.romneyY))
    .filter(d => d.obamaY < d.romneyY); // smaller y is higher on chart

  // Draw connectors
  let connectorsG = scene2.select('g.obama-gt-connectors');
  if (connectorsG.empty()) {
    connectorsG = scene2.append('g')
      .attr('class', 'obama-gt-connectors')
      .attr('fill', 'none')
      .attr('stroke', '#111827')
      .attr('stroke-width', 1.25)
      .attr('opacity', 0.35);
  }

  connectorsG.selectAll('line')
    .data(pairs, d => d.x)
    .join('line')
    .attr('x1', d => d.x)
    .attr('x2', d => d.x)
    .attr('y1', d => d.obamaY)
    .attr('y2', d => d.romneyY);

  // Highlight Obama points where Obama > Romney
  obamaCircles
    .attr('opacity', 0.35)
    .attr('stroke', 'none')
    .attr('stroke-width', null);

  pairs.forEach(d => {
    d.obamaCircle
      .attr('opacity', 1)
      .attr('stroke', '#111827')
      .attr('stroke-width', 1.5);
  });

  // Counter label (top-right inside plot)
  const labelX = 332, labelY = 44, labelW = 170, labelH = 30;

  let labelRect = scene2.select('rect.scene-2-counter');
  if (labelRect.empty()) {
    labelRect = scene2.append('rect').attr('class', 'scene-2-counter');
  }
  labelRect
    .attr('x', labelX)
    .attr('y', labelY)
    .attr('width', labelW)
    .attr('height', labelH)
    .attr('rx', 6)
    .attr('ry', 6)
    .attr('fill', '#ffffff')
    .attr('stroke', '#111827')
