(function(){
  const svg = d3.select('svg');
  const layer = svg.select('.annotation-layer.operation-next-annotation-layer');
  if (layer.empty()) return;

  // Clear and rebuild this scene's compare annotations
  layer.selectAll('*').remove();

  const plotG = svg.select('g[transform="translate(101.28101189543155,40)"]');
  const bars = plotG.selectAll('rect.main-bar');

  const years = ['2016','2017','2018','2019','2020','2021'];

  function num(v){ return +String(v).replace(/,/g,''); }

  // Shadow filter
  const defs = layer.append('defs');
  const f = defs.append('filter')
    .attr('id','calloutShadow')
    .attr('x','-20%').attr('y','-20%')
    .attr('width','140%').attr('height','140%');
  f.append('feDropShadow')
    .attr('dx',0).attr('dy',1).attr('stdDeviation',1)
    .attr('flood-color','#000').attr('flood-opacity',0.18);

  const root = layer.append('g')
    .attr('class','th-ph-compare')
    .attr('font-family','sans-serif');

  years.forEach(year => {
    const th = bars.filter(function(){
      const r = d3.select(this);
      return r.attr('data-target')===year && r.attr('data-series')==='Thailand';
    });
    const ph = bars.filter(function(){
      const r = d3.select(this);
      return r.attr('data-target')===year && r.attr('data-series')==='Philippines';
    });
    if (th.empty() || ph.empty()) return;

    const thNode = th.node();
    const phNode = ph.node();

    const x = +th.attr('x');
    const w = +th.attr('width');

    const thY = +th.attr('y');
    const thH = +th.attr('height');
    const phY = +ph.attr('y');
    const phH = +ph.attr('height');

    const thMid = thY + thH/2;
    const phMid = phY + phH/2;

    const thVal = num(th.attr('data-value'));
    const phVal = num(ph.attr('data-value'));

    const cmp = thVal > phVal ? 'TH > PH' : 'TH < PH';

    const rightEdge = x + w;
    const bracketX0 = rightEdge;
    const bracketX1 = rightEdge + 9;
    const calloutX = rightEdge + 17;

    const g = root.append('g').attr('class','year-compare').attr('data-year',year);

    // Bracket/connector
    g.append('path')
      .attr('d',`M${bracketX0},${thMid} L${bracketX1},${thMid}`)
      .attr('fill','none').attr('stroke','#111').attr('stroke-width',1).attr('opacity',0.7);
    g.append('path')
      .attr('d',`M${bracketX0},${phMid} L${bracketX1},${phMid}`)
      .attr('fill','none').attr('stroke','#111').attr('stroke-width',1).attr('opacity',0.7);
    g.append('path')
      .attr('d',`M${bracketX1},${Math.min(thMid,phMid)} L${bracketX1},${Math.max(thMid,phMid)}`)
      .attr('fill','none').attr('stroke','#111').attr('stroke-width',1).attr('opacity',0.7);

    // Small connector lines to callouts
    g.append('line')
      .attr('x1', bracketX0).attr('y1', thMid)
      .attr('x2', calloutX-2).attr('y2', thMid)
      .attr('stroke', '#10b981').attr('stroke-width', 1).attr('opacity', 0.9);
    g.append('line')
      .attr('x1', bracketX0).attr('y1', phMid)
      .attr('x2', calloutX-2).attr('y2', phMid)
      .attr('stroke', '#f59e0b').attr('stroke-width', 1).attr('opacity', 0.9);

    // Callout boxes
    function callout(y, stroke, text){
      const boxW = Math.max(92, text.length * 6.2 + 18);
      const boxH = 18;
      const cg = g.append('g').attr('transform', `translate(${calloutX},${y - boxH/2})`);
      cg.append('rect')
        .attr('x',0).attr('y',0)
        .attr('width',boxW).attr('height',boxH)
        .attr('rx',3).attr('ry',3)
        .attr('fill','#fff')
        .attr('stroke',stroke)
        .attr('stroke-width',1)
        .attr('filter','url(#calloutShadow)');
      cg.append('text')
        .attr('x',6).attr('y',13)
        .attr('font-size',12)
        .attr('fill','#111')
        .text(text);
      return boxW;
    }

    const thText = `TH: ${th.attr('data-value')}`;
    const phText = `PH: ${ph.attr('data-value')}`;
    const thW = callout(thMid, '#10b981', thText);
    const phW = callout(phMid, '#f59e0b', phText);

    // Comparison marker below the lower callout
    const lowerMid = Math.max(thMid, phMid);
    g.append('text')
      .attr('x', calloutX)
      .attr('y', lowerMid + 16)
      .attr('font-size', 12)
      .attr('fill', '#111')
      .attr('font-weight', 700)
      .text(cmp);
  });
})();

