      .attr('flood-color','#000').attr('flood-opacity',0.18);
  }

  const tally = layer.selectAll('g.th-ph-tally').data([count]);
  const tallyEnter = tally.enter().append('g')
    .attr('class','th-ph-tally')
    .attr('transform','translate(10,10)');

  tallyEnter.append('rect')
