  tallyEnter.append('text')
    .attr('x',10).attr('y',19)
    .attr('font-family','sans-serif')
    .attr('font-size',14)
    .attr('fill','#111')
    .attr('font-weight',700)
    .text('Years with TH > PH: ')
    .append('tspan')
    .attr('class','tally-value')
    .attr('fill','#10b981')
    .text(count);

  tally.select('tspan.tally-value').text(d => d);

  // --- Add check / x marks above year ticks ---
  const xAxis = plotG.select('g.x-axis');
  const ticks = xAxis.selectAll('g.tick');

  ticks.each(function(){
    const tick = d3.select(this);
    const year = tick.select('text tspan').text();
    if (!years.includes(year)) return;

    const th = bars.filter(function(){
      const r = d3.select(this);
      return r.attr('data-target')===year && r.attr('data-series')==='Thailand';
